import 'package:equatable/equatable.dart'; class LocationEntity extends Equatable { final double latitude; final double longitude; final double? accuracy; final double? altitude; final double? speed; final DateTime timestamp; const LocationEntity({required this.latitude, required this.longitude, this.accuracy, this.altitude, this.speed, required this.timestamp}); @override List<Object?> get props => [latitude, longitude, timestamp]; String get formatted => '${latitude.toStringAsFixed(5)}, ${longitude.toStringAsFixed(5)}'; }
